import React from 'react';
import { Menu as MenuIcon, Globe, Sun, Moon } from 'lucide-react';
import UserMenu from './UserMenu';

interface HeaderProps {
  lang: 'pt' | 'en';
  theme: 'light' | 'dark';
  setLang: (lang: 'pt' | 'en') => void;
  setTheme: (theme: 'light' | 'dark') => void;
  isSidebarOpen: boolean;
  setIsSidebarOpen: (open: boolean) => void;
  onLogout: () => void;
  isUserMenuOpen: boolean;
  setIsUserMenuOpen: (open: boolean) => void;
  logout: string;
}

const Header: React.FC<HeaderProps> = ({ 
  lang, 
  theme, 
  setLang, 
  setTheme, 
  isSidebarOpen, 
  setIsSidebarOpen, 
  onLogout, 
  isUserMenuOpen, 
  setIsUserMenuOpen,
  logout 
}) => {
  return (
    <header className={`h-16 px-4 flex items-center justify-between border-b shrink-0 ${theme === 'dark' ? 'border-slate-800 bg-slate-900' : 'border-slate-200 bg-white'}`}>
      <div className="flex items-center gap-4">
        <button 
          onClick={() => setIsSidebarOpen(!isSidebarOpen)}
          className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-lg lg:hidden"
        >
          <MenuIcon size={24} />
        </button>
        <div className="flex items-center gap-2">
          <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center text-white font-bold">eC</div>
          <span className="font-bold text-lg hidden sm:block">enContact</span>
        </div>
      </div>

      <div className="flex items-center gap-3">
        <button onClick={() => setLang(lang === 'pt' ? 'en' : 'pt')} className="p-2 rounded-lg hover:bg-slate-100 dark:hover:bg-slate-800 flex items-center gap-2 text-sm">
          <Globe size={18} />
          <span className="uppercase">{lang}</span>
        </button>
        <button onClick={() => setTheme(theme === 'dark' ? 'light' : 'dark')} className="p-2 rounded-lg hover:bg-slate-100 dark:hover:bg-slate-800">
          {theme === 'dark' ? <Sun size={18} /> : <Moon size={18} />}
        </button>
        
        <UserMenu 
          isUserMenuOpen={isUserMenuOpen}
          setIsUserMenuOpen={setIsUserMenuOpen}
          onLogout={onLogout}
          theme={theme}
          logout={logout}
        />
      </div>
    </header>
  );
};

export default Header;
